dtsPropsFor.BlockRenderer:
/** The ordered list of blocks in one agent message. Each item is one of the block specs documented by the *BlockView components (discriminated by `type`). */
  blocks: Array<{ type: string; id?: string; confidence?: "high" | "medium" | "low"; collapsed?: boolean; summary?: string; [key: string]: unknown }>;
  /** Called with every pending selection as ONE batch when the user submits. */
  onRespond?: (responses: { blockId: string; type: string; value: unknown }[]) => void;
  /** Map of progress-block id -> latest progress seen, so older messages re-render with current progress. */
  progressOverrides?: Record<string, { type: "progress"; id?: string; title?: string; steps: { label: string; status: "done" | "active" | "pending" | "failed" }[] }>;
